	sscanf(*str, "%d%n", &info, &read_chars);
	*str += read_chars;

	// Leggi sottoalberi
	TipoAlbero left, right;
	leggiAlberoStringaAux(left, str);
	leggiAlberoStringaAux(right, str);

	// Fine albero
