		fprintf(stderr, "Incorretta stringa parentetica\n");
		return 		albBinVuoto();
	}
	++(*str);

	return creaAlbBin(info, left, right);
}

TipoAlbero leggiAlberoStringa(TipoAlbero a, const char *str) {
	const char *s = str;
	return leggiAlberoStringaAux(a, &s);
