Mat *mat_alloc(int rows, int cols)
{

	Mat *m = (Mat *)malloc(sizeof(Mat));

	m->cols = cols;
	m->rows = rows;
	m->mat = (double **)malloc(sizeof(double *) * rows);

	double *row_p = (double *)malloc(sizeof(double) * rows * cols);
	for (int i = 0; i < rows; ++i)
	{
		m->mat[i] = row_p;
		row_p += cols;
	}

	return m;
}

