bool filtro(TipoInfoAlbero c) {
	static int chosen[6];
	static int initialized = 0;
	if (!initialized) {
		unsigned int seed = 12345;
		srand(seed);
		int count = 0;
		while (count < 6) {
			int val = 1 + rand() % 10;
			int duplicate = 0;
			for (int i = 0; i < count; ++i) {
				if (chosen[i] == val) {
					duplicate = 1;
					break;
				}
			}
			if (!duplicate) {
				chosen[count++] = val;
			}
		}
		initialized = 1;
	}
	for (int i = 0; i < 6; ++i) {
		if (c == chosen[i]) return true;
	}
	return false;
}

