{

	Mat *m = (Mat *)malloc(sizeof(Mat));

	m->cols = cols;
	m->rows = rows;
	m->mat = (char **)malloc(sizeof(double *) * rows);

	char *row_p = (char *)malloc(sizeof(double) * rows * cols);
	for (int i = 0; i < rows; ++i)
	{
		m->mat[i] = row_p;
		row_p += cols;
	}

