    tree_to_string_rec(a->sinistro, buf, cap, pos);
    if (*pos + 1 < cap) { buf[(*pos)++] = ' '; buf[*pos] = '\0'; }
    tree_to_string_rec(a->destro, buf, cap, pos);
    if (*pos + 1 < cap) { buf[(*pos)++] = ')'; buf[*pos] = '\0'; }
